use anyhow::Result;
use camino::Utf8PathBuf;
use chrono::Utc;
use clap::Parser;
use semver::Version;
use tufaceous::edit::RepositoryEditor;
use tufaceous_artifact::KnownArtifactTags;

use crate::load::LoadOptions;
use crate::sign::SignOptions;

#[derive(Debug, Parser)]
pub struct Args {
    /// Artifacts to add to the repository
    ///
    /// For OS images, use the directory generated by helios-build that contains
    /// zfs.img, gimlet.rom, etc.
    #[arg(short = 'a', long, num_args(1..))]
    add_artifacts: Vec<Utf8PathBuf>,
    #[clap(flatten)]
    load_options: LoadOptions,
    /// Do not generate a new Installinator document, and leave the existing
    /// Installinator document if one exists
    #[clap(long)]
    no_installinator_document: bool,
    /// ZIP archive output path [default: rewrite input repository]
    #[clap(short = 'o', long)]
    output: Option<Utf8PathBuf>,
    /// Targets to remove from the repository
    ///
    /// These are the paths under "repo/targets/" in a ZIP archive. The
    /// list-targets command lists the target names.
    #[arg(short = 'd', long, num_args(1..))]
    remove_targets: Vec<String>,
    /// Input repository path
    repo: Utf8PathBuf,
    #[clap(flatten)]
    sign_options: SignOptions,
    /// Edit the system version
    #[clap(short = 'V', long)]
    system_version: Option<Version>,
}

impl Args {
    pub async fn run(self) -> Result<()> {
        let repo = self
            .load_options
            .loader()
            .await?
            .load_zip_path(self.repo.clone(), &crate::LOG)
            .await?;
        let mut editor = RepositoryEditor::from_repo(&repo)?
            .set_generate_installinator_document(
                !self.no_installinator_document,
            );

        if !self.no_installinator_document {
            editor = editor
                .remove_artifacts(&KnownArtifactTags::InstallinatorDocument)?;
        }

        if let Some(system_version) = self.system_version {
            editor = editor.set_system_version(system_version)?;
        }
        for target_name in &self.remove_targets {
            editor = editor.remove_target(target_name);
        }
        for path in self.add_artifacts {
            editor = editor.guess_artifact(path).await?;
        }

        let unsigned = editor.finish().await?;
        let output = self.output.unwrap_or(self.repo);
        self.sign_options
            .sign(unsigned)
            .await?
            .write_zip_file(output, Utc::now())
            .await?;
        Ok(())
    }
}
